import React from "react";
import type { Lang } from "@/content/translations";

export type CoverSize = "sm" | "md" | "lg";

// Natural aspect ratios of the cropped cover JPEGs in public/covers/.
// Re-run scripts/process-covers.js and update these numbers if the source art
// is ever replaced — BookCover sizes its container from these so there is
// never any letterbox / pillarbox inside the frame.
const NATURAL_AR: Record<Lang, number> = {
  ar: 0.676, // 461 / 682 — front half with 5% back-cover-bleed gutter removed
  en: 0.627, // 538 / 858 — symmetric 40px top/bottom pad (well under prev 105px)
};

// One width per size; height is computed from the per-language aspect below.
const WIDTH: Record<CoverSize, number> = {
  sm: 220,
  md: 340,
  lg: 440,
};

/**
 * Renders the real book cover photograph for Arabic,
 * and the English poster artwork for English.
 */
export const BookCover: React.FC<{
  lang: Lang;
  size?: CoverSize;
  className?: string;
  alt?: string;
}> = ({ lang, size = "md", className = "", alt }) => {
  const w = WIDTH[size];
  const h = Math.round(w / NATURAL_AR[lang]);
  const base = import.meta.env.BASE_URL;
  const src =
    lang === "ar" ? `${base}covers/ar-cover.jpg` : `${base}covers/en-poster.jpg`;
  const fallbackAlt =
    lang === "ar"
      ? "غلاف كتاب الحضارة المصرية القديمة — رؤية عقلية موثّقة"
      : "Esoteric Messages from Ancient Egypt — book poster";
  return (
    <div
      className={`relative overflow-hidden ${className}`}
      style={{ width: w, height: h, background: "#0b0908" }}
    >
      <img
        src={src}
        alt={alt ?? fallbackAlt}
        width={w}
        height={h}
        loading="lazy"
        className="absolute inset-0 h-full w-full object-cover"
      />
    </div>
  );
};
